"use strict";parserFactory.register("japtem.com",()=>new JaptemParser);class JaptemParser extends Parser{constructor(){super()}getChapterUrls(e){let t=this.findContent(e);return Promise.resolve(util.hyperlinksToChapterList(t))}findContent(e){return e.querySelector("div.post-content")}findParentNodeOfChapterLinkToRemoveAt(e){return util.moveIfParent(e,"h2")}}